import * as fs from 'fs';
import * as path from 'path';

export async function doStep(i: number): Promise<void> {
  const logPath = '/workspace/progress.log';
  fs.appendFileSync(logPath, `step ${i}\n`);
}

import * as workflow from '@temporalio/workflow';
import type { doStep as doStepActivity } from './activities';

const { sleep, proxyActivities, defineQuery, setHandler } = workflow;

const activities = proxyActivities<{ doStep: typeof doStepActivity }>({
  startToCloseTimeout: '30s',
});

export const getProgressQuery = defineQuery<{ progress: number; currentStep: number; total: number }>('getProgress');

export async function ProgressWorkflow(totalSteps: number): Promise<{ progress: number; currentStep: number; total: number }> {
  let progress = 0;
  let currentStep = 0;

  setHandler(getProgressQuery, () => ({
    progress,
    currentStep,
    total: totalSteps,
  }));

  for (let i = 1; i <= totalSteps; i++) {
    await activities.doStep(i);
    currentStep = i;
    progress = i / totalSteps;
    if (i < totalSteps) {
      await sleep('1s');
    }
  }

  return { progress, currentStep, total: totalSteps };
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';
import * as path from 'path';

const TEMPORAL_ADDRESS = process.env.TEMPORAL_ADDRESS!;
const TEMPORAL_API_KEY = process.env.TEMPORAL_API_KEY!;
const TEMPORAL_NAMESPACE = process.env.TEMPORAL_NAMESPACE!;

async function main() {
  const connection = await NativeConnection.connect({
    address: TEMPORAL_ADDRESS,
    tls: true,
    apiKey: TEMPORAL_API_KEY,
    metadata: {
      'temporal-namespace': TEMPORAL_NAMESPACE,
    },
  });

  const worker = await Worker.create({
    connection,
    namespace: TEMPORAL_NAMESPACE,
    taskQueue: 'progress-ts',
    workflowsPath: path.resolve(__dirname, './workflow'),
    activities,
  });

  console.log('Worker started on task queue: progress-ts');
  await worker.run();
}

main().catch((err) => {
  console.error('Worker error:', err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { ProgressWorkflow, getProgressQuery } from './workflow';
import * as fs from 'fs';

const TEMPORAL_ADDRESS = process.env.TEMPORAL_ADDRESS!;
const TEMPORAL_API_KEY = process.env.TEMPORAL_API_KEY!;
const TEMPORAL_NAMESPACE = process.env.TEMPORAL_NAMESPACE!;
const ZEALT_RUN_ID = process.env.ZEALT_RUN_ID!;

async function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function main() {
  const workflowId = `progress-${ZEALT_RUN_ID}`;

  const connection = await Connection.connect({
    address: TEMPORAL_ADDRESS,
    tls: true,
    apiKey: TEMPORAL_API_KEY,
    metadata: {
      'temporal-namespace': TEMPORAL_NAMESPACE,
    },
  });

  const client = new Client({
    connection,
    namespace: TEMPORAL_NAMESPACE,
  });

  console.log(`Starting workflow with id: ${workflowId}`);
  const handle = await client.workflow.start(ProgressWorkflow, {
    taskQueue: 'progress-ts',
    workflowId,
    args: [5],
  });

  console.log(`Workflow started. Waiting 2.5 seconds before querying...`);
  await sleep(2500);

  console.log('Sending getProgress query...');
  const progressResult = await handle.query(getProgressQuery);
  console.log('Query result:', progressResult);

  fs.writeFileSync('/workspace/progress.json', JSON.stringify(progressResult));
  console.log('Written progress.json:', progressResult);

  console.log('Awaiting final workflow result...');
  const finalResult = await handle.result();
  console.log('Final result:', finalResult);
}

main().catch((err) => {
  console.error('Client error:', err);
  process.exit(1);
});

